// ============================================================
// CSV読み込み: data/*.csv があればそれを優先、失敗時はFALLBACKを使う
// ============================================================
let DATA = [];
let POSTING = [];
let KAWAI = [];

function parseCSV(text) {
  const lines = text.trim().split('\n');
  const headers = lines[0].split(',').map(h => h.trim());
  return lines.slice(1).filter(l => l.trim()).map(line => {
    const values = line.split(',');
    const obj = {};
    headers.forEach((h, i) => {
      const v = (values[i] ?? '').trim();
      obj[h] = v === '' || isNaN(v) ? v : Number(v);
    });
    return obj;
  });
}

async function loadCSVData() {
  try {
    const [houseRes, senateRes, postingRes, candidateRes] = await Promise.all([
      fetch('data/house.csv'),
      fetch('data/senate.csv'),
      fetch('data/posting.csv'),
      fetch('data/candidate.csv'),
    ]);

    if (!houseRes.ok || !senateRes.ok || !postingRes.ok) {
      throw new Error('CSV fetch failed');
    }

    const house = parseCSV(await houseRes.text());
    const senate = parseCSV(await senateRes.text());
    const posting = parseCSV(await postingRes.text());
    const candidate = candidateRes.ok ? parseCSV(await candidateRes.text()) : [];

    const senateMap = {};
    senate.forEach(d => { senateMap[d['地域']] = d; });

    DATA = house.map(h => {
      const s = senateMap[h['地域']] || {};
      const houseRate = h['得票率'];
      const senateRate = s['得票率'] || 0;
      return {
        '地域': h['地域'],
        'チームみらい': h['得票数'],
        'チームみらい率': houseRate,
        '合計': h['合計'],
        'チームみらい_参票数': s['得票数'] || 0,
        'チームみらい率_参': senateRate,
        '衆参差': Math.round((houseRate - senateRate) * 10) / 10,
      };
    });

    POSTING = posting;
    KAWAI = candidate;

    console.log(`CSV loaded: ${DATA.length} municipalities, ${POSTING.length} posting, ${KAWAI.length} candidates`);
  } catch (e) {
    console.warn('CSV load failed, using fallback data:', e.message);
    DATA = FALLBACK_DATA;
    POSTING = FALLBACK_POSTING;
    KAWAI = FALLBACK_KAWAI;
  }
}
